    'age': [25, None, 35, 28],
    'score': [88.5, 92.0, 76.5, None]
}

num_records = len(list(data.values())[0])
num_fields = len(data)

print(f"Records: {num_records}")
print(f"Fields: {num_fields}")
print()
for field, values in data.items():
    missing = sum(1 for v in values if v is None)
    non_none = [v for v in values if v is not None]
    if non_none and isinstance(non_none[0], str):
        dtype = "string"
    elif non_none and isinstance(non_none[0], float):
        dtype = "float"
    else:
        dtype = "integer"
    print(f"{field}: type={dtype}, missing={missing}")

