exercises.solution:
records = [
    {'name': 'Widget A', 'price': 29.99, 'quantity': 100, 'discount': 10},
    {'name': 'Widget B', 'price': -5.00, 'quantity': 50, 'discount': 80},
    {'name': 'Widget C', 'price': 49.99, 'quantity': -10, 'discount': 15},
    {'name': 'Widget D', 'price': 19.99, 'quantity': 200, 'discount': 5},
]

passed = 0
total = len(records)

print("Validation Results:")
for rec in records:
    violations = []
    if rec['price'] <= 0:
        violations.append("price must be > 0")
    if rec['quantity'] < 0:
        violations.append("quantity must be >= 0")
    if rec['discount'] < 0 or rec['discount'] > 50:
        violations.append("discount must be 0-50")

    if not violations:
        passed += 1
        print(f"  {rec['name']}: PASS")
    else:
        print(f"  {rec['name']}: FAIL")
        for v in violations:
            print(f"    - {v}")

print(f"\nPass Rate: {passed}/{total} ({passed/total*100:.0f}%)")
